{
    "level": "B1",
    "intro": "У цій темі ти навчишся розрізняти <strong>another, other, the other</strong>, а також <strong>others / the others</strong>.",
    "rules": [
        {
            "label": "ONE MORE",
            "color": "emerald",
            "text": "<strong>Another</strong> = ще один або інший один предмет.",
            "example": "Can I have another coffee?"
        },
        {
            "label": "DIFFERENT / MORE",
            "color": "blue",
            "text": "<strong>Other</strong> вживаємо з множиною або незлічуваними іменниками.",
            "example": "other people / other information"
        },
        {
            "label": "THE REMAINING ONE",
            "color": "amber",
            "text": "<strong>The other</strong> = той другий / той, що залишився.",
            "example": "One bag is mine, and the other bag is yours."
        }
    ]
}

{
    "title": "1. Основні відмінності",
    "intro": "Подивись, яка форма з яким типом іменника працює.",
    "items": [
        {
            "label": "один предмет",
            "title": "another + singular noun",
            "subtitle": "another day, another cup, another idea"
        },
        {
            "label": "інші / додаткові",
            "title": "other + plural / uncountable noun",
            "subtitle": "other books, other people, other information"
        },
        {
            "label": "конкретний другий",
            "title": "the other + singular noun",
            "subtitle": "the other hand, the other room"
        },
        {
            "label": "без іменника",
            "title": "others / the others",
            "subtitle": "Some are ready; the others are late."
        }
    ]
}

{
    "title": "2. Коли вживати кожну форму",
    "sections": [
        {
            "label": "Another = ще один",
            "color": "emerald",
            "description": "<strong>Another</strong> поєднується з одниною і часто означає «ще один» або «інший» із подібної групи.",
            "examples": [
                {
                    "en": "Can I have another sandwich?",
                    "ua": "Можна мені ще один сендвіч?"
                },
                {
                    "en": "Let us try another method.",
                    "ua": "Давай спробуємо інший метод."
                },
                {
                    "en": "She stayed for another hour.",
                    "ua": "Вона залишилася ще на одну годину."
                }
            ]
        },
        {
            "label": "Other = інші / додаткові",
            "color": "blue",
            "description": "<strong>Other</strong> стоїть перед множиною або незлічуваним іменником.",
            "examples": [
                {
                    "en": "Other students were already inside.",
                    "ua": "Інші студенти вже були всередині."
                },
                {
                    "en": "Do you have any other questions?",
                    "ua": "У вас є ще якісь інші питання?"
                },
                {
                    "en": "We need other information.",
                    "ua": "Нам потрібна інша інформація."
                }
            ]
        },
        {
            "label": "The other / the others = той, що залишився",
            "color": "amber",
            "description": "<strong>The other</strong> — конкретний другий або останній один; <strong>the others</strong> — решта з групи.",
            "examples": [
                {
                    "en": "I have two keys. One is old and the other is new.",
                    "ua": "У мене два ключі. Один старий, а другий новий."
                },
                {
                    "en": "Some students passed, but the others failed.",
                    "ua": "Деякі студенти склали, а решта — ні."
                },
                {
                    "en": "This side is clean. The other side is dirty.",
                    "ua": "Цей бік чистий. Інший бік брудний."
                }
            ],
            "note": "Без іменника використовуємо <strong>others / the others</strong>, а не <span class=\"line-through\">other ones</span> за замовчуванням."
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Another з множиною.",
            "wrong": "another books",
            "right": "✅ <span class=\"font-mono\">other books</span> / <span class=\"font-mono\">another book</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Other без іменника, коли треба others.",
            "wrong": "Some students are here, and other are late.",
            "right": "✅ <span class=\"font-mono\">Some students are here, and others are late.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Пропуск the в конкретному значенні.",
            "wrong": "One shoe is black, other shoe is brown.",
            "right": "✅ <span class=\"font-mono\">One shoe is black, the other shoe is brown.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "<strong>Another</strong> = ще один / інший один предмет.",
        "<strong>Other</strong> = інші або додаткові речі / люди; йде з множиною або незлічуваним іменником.",
        "<strong>The other</strong> = конкретний другий або той, що залишився.",
        "<strong>Others / the others</strong> використовуємо без іменника.",
        "Питай себе: це ще один, інші взагалі чи конкретний той, що залишився?"
    ]
}

